{
  "subject_and_scene": {
    "main_subject": "一位心碎、灵魂崩溃的中世纪骑士跪在失败中，他的眼睛里充满了泪水和创伤；他破碎的盔甲上沾满了干泥和新鲜的血液。他的脸上布满伤疤、汗水和污垢，反映出一个没落王国的悲惨损失。",
    "action": "他用颤抖的双手握住剑柄，仿佛这是唯一能让他不至于崩溃的东西；他的胸口因绝望而有节奏地剧烈喘息。",
    "environment": "古老森林边缘荒凉、狂风肆虐的战场；一层朦胧、空灵的雾气在地面上翻滚，遮住了远处正在冒烟的城堡废墟的一部分。花瓣或余烬随风飘过，飘过他的脸。"
  },
  "cinematography": {
    "camera_model": "索尼威尼斯2",
    "sensor_type": "全画幅",
    "shot_type": "中特写（垂直构图，重点关注骑士的躯干和脸部，但保持他的跪姿可见）",
    "camera_angle": "低角度（略微倾斜的荷兰角，以唤起心理不稳定和悲伤的感觉）",
    "movement": "缓慢的“Dolly In”与“Snorricam”效果相结合，使骑士的斗争感觉幽闭恐怖且强烈个人化"
  },
  "optics": {
    "lens_type": "变形（创造情感“梦幻般”的衰减和戏剧性的耀斑）",
    "focal_length": "50mm（提供自然但情感集中的视角）",
    "aperture": "f/1.4（景深极浅，除了他充满泪水的眼睛之外，一切都模糊了）",
    "shutter_effects": "180 度快门可对被风吹动的碎片进行自然运动模糊，强调“慢动作”的悲伤感"
